input.command:
PW=$(kubectl -n elasticsearch get secret elastic-password -o jsonpath="{.data.password}" | base64 -d)
kubectl -n elasticsearch exec curl-test -- curl -sk -u "elastic:$PW" -XPOST \
  "https://es-http.elasticsearch.svc:9200/_bulk" \
  -H "Content-Type: application/x-ndjson" \
  --data-binary $'{"index":{"_index":"app-events"}}
{"service":"api","@timestamp":"2026-06-17T10:00:00Z","event":"request"}
{"index":{"_index":"app-events"}}
{"service":"web","@timestamp":"2026-06-17T10:00:01Z","event":"page_view"}
{"index":{"_index":"app-events"}}
{"service":"worker","@timestamp":"2026-06-17T10:00:02Z","event":"job_complete"}
{"index":{"_index":"app-events"}}
{"service":"api","@timestamp":"2026-06-17T10:00:03Z","event":"response"}
' \
  2>&1 | python3 -c "import json,sys; d=json.load(sys.stdin); print('errors:', d.get('errors'), 'items:', len(d.get('items',[])))"

